import Link from '../../components/Link';
const _not_found = {title: "Unknown", jsx: <><h2 id="druiddomain-not_found-error">Error</h2>
<p>Unable to find the requested druidic domain.</p>
</>};
const _aquatic = {title: "Aquatic", jsx: <><h2 id="druiddomain-aquatic-aquatic-domain">Aquatic Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 33</Link></p>
<p><strong>Granted Powers:</strong> You master the deeps of the sea, raging rivers, flowing falls, and relentless tides.</p>
<p><strong>Sealord (Su):</strong> You can <Link to="/ability/channel_energy">channel energy</Link> (as a cleric of your druid level) a number of times per day equal to 3 + your Charisma modifier, but only to heal creatures with the aquatic or water subtype or to command them (similar to using the <Link to="/feat/command_undead">Command Undead</Link> feat against undead). You can take other feats to add to this ability, such as <Link to="/feat/extra_channel">Extra Channel</Link> and <Link to="/feat/improved_channel">Improved Channel</Link>, but not feats that alter this ability, such as <Link to="/feat/elemental_channel">Elemental Channel</Link> and <Link to="/feat/alignment_channel">Alignment Channel</Link>. The DC to save against this ability is equal to 10 + 1/2 your druid level + your Charisma modifier.</p>
<p><strong>Seastrike (Su):</strong> At 6th level, as a free action, you may use natural and manufactured weapons in water as if you had continuous <em>freedom of movement.</em> As a standard action, you can throw a weapon underwater without the normal penalties for throwing weapons; if your target is in or under the water, the weapon also acts as a <Link to="/magic-enh/returning">returning</Link> weapon for that attack.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/hydraulic_push">hydraulic push</Link>, 2nd-<Link to="/spell/slipstream">slipstream</Link>, 3rd-<Link to="/spell/water_breathing">water breathing</Link>, 4th-<Link to="/spell/freedom_of_movement">freedom of movement</Link>, 5th-<Link to="/spell/black_tentacles">black tentacles</Link>, 6th-<Link to="/spell/freezing_sphere">freezing sphere</Link>, 7th-<Link to="/spell/animal_shapes">animal shapes</Link> (aquatic creatures only), 8th-<Link to="/spell/seamantle">seamantle</Link>, 9th-<Link to="/spell/tsunami">tsunami</Link>.</p>
</>};
const _arctic = {title: "Arctic", jsx: <><h2 id="druiddomain-arctic-arctic-domain">Arctic Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 33</Link></p>
<p><strong>Granted Powers:</strong> You master the might of the endless, snow-covered wastes beneath the midnight sun, where icy polar winds blow.</p>
<p><strong>Call Cold (Su):</strong> You can <Link to="/ability/channel_energy">channel energy</Link> (as a cleric of your druid level) a number of times per day equal to 3 + your Charisma modifier, but only to heal creatures with the cold subtype or to command them (similar to using the <Link to="/feat/command_undead">Command Undead</Link> feat against undead). You can take other feats that add to this ability, such as <Link to="/feat/extra_channel">Extra Channel</Link> and <Link to="/feat/improved_channel">Improved Channel</Link>, but not feats that alter this ability, such as <Link to="/feat/elemental_channel">Elemental Channel</Link> and <Link to="/feat/alignment_channel">Alignment Channel</Link>. The DC to save against this ability is equal to 10 + 1/2 your druid level + your Charisma modifier.</p>
<p><strong>Banish Flame (Su):</strong> At 6th level, you may use your call cold ability to damage creatures with the fire subtype (as a cleric channeling negative energy) or to cause them to flee from you (as the <Link to="/feat/turn_undead">Turn Undead</Link> feat). Alternatively, you may use this ability to negate magical fire effects as if using a targeted <Link to="/spell/dispel_magic">dispel magic</Link>; at 12th level, this functions as targeted or area <Link to="/spell/greater_dispel_magic">greater dispel magic</Link> instead of dispel magic.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/frostbite">frostbite</Link>, 2nd-<Link to="/spell/aspect_of_the_bear">aspect of the bear</Link>, 3rd-<Link to="/spell/sleet_storm">sleet storm</Link>, 4th-<Link to="/spell/wall_of_ice">wall of ice</Link>, 5th-<Link to="/spell/aspect_of_the_wolf">aspect of the wolf</Link>, 6th-<Link to="/spell/freezing_sphere">freezing sphere</Link>, 7th-<Link to="/spell/wind_walk">wind walk</Link>, 8th-<Link to="/spell/polar_ray">polar ray</Link>, 9th-<Link to="/spell/polar_midnight">polar midnight</Link>.</p>
</>};
const _badlands = {title: "Badlands", jsx: <><h2 id="druiddomain-badlands-badlands-domain">Badlands Domain</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 24</Link></p>
<p><strong>Granted Powers:</strong> Your spirit knows both the harshness of the drying wind and the raw beauty of painted canyons.</p>
<p><strong>Subsistence (Ex):</strong> You can survive on very little food or water while helping others survive in harsh climates. When determining how long you can withstand starvation and thirst, including checks to avoid nonlethal damage, treat your Constitution score as though it were 10 points higher. Additionally, you gain a bonus equal to one half your druid level (minimum 1) on Survival checks in dry hills or desert terrain.</p>
<p><strong>Wasteland Stride (Ex):</strong> At 2nd level, you may move through light or dense rubble, as well as up or down steep slopes, at your normal speed without suffering any impairment. Areas that have been magically manipulated to impede motion still affect you, however.</p>
<p>This replaces <strong className="hl">woodland stride</strong>.</p>
<p><strong>Badlands Spirit (Su):</strong> At 8th level, whenever you use wild shape to take on the form of an earth elemental, you also gain the following spell-like abilities, depending on your druid class level: <Link to="/spell/geyser">geyser</Link> (8th); <Link to="/spell/sirocco">sirocco</Link> (12th), <Link to="/spell/scouring_winds">scouring winds</Link> (15th). Each spell-like ability is usable once per day.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/cloak_of_shade">cloak of shade</Link>, 2nd-<Link to="/spell/feast_of_ashes">feast of ashes</Link>, 3rd-<Link to="/spell/cloak_of_winds">cloak of winds</Link>, 4th-<Link to="/spell/spike_stones">spike stones</Link>, 5th-<Link to="/spell/wind_blades">wind blades</Link>, 6th-<Link to="/spell/find_the_path">find the path</Link>, 7th-<Link to="/spell/fire_storm">fire storm</Link>, 8th-<Link to="/spell/earthquake">earthquake</Link>, 9th-<Link to="/spell/storm_of_vengeance">storm of vengeance</Link>.</p>
</>};
const _cave = {title: "Cave", jsx: <><h2 id="druiddomain-cave-cave-domain">Cave Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 33</Link></p>
<p><strong>Granted Powers:</strong> The wonders and dark secrets of the deepest caves give you strength.</p>
<p><strong>Cavesight (Sp):</strong> You can grant darkvision 60 feet to a willing creature you touch. This effect lasts 1 minute, or 1 hour if used on yourself. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Tremorsense (Ex):</strong> At 6th level, you gain <Link to="/umr/tremorsense">tremorsense</Link> 30 feet. At 12th level, you gain tremorsense 60 feet.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/detect_aberration">detect aberration</Link>, 2nd-<Link to="/spell/stone_call">stone call</Link>, 3rd-<Link to="/spell/deeper_darkness">deeper darkness</Link>, 4th-<Link to="/spell/echolocation">echolocation</Link>, 5th-<Link to="/spell/wall_of_stone">wall of stone</Link>, 6th-<Link to="/spell/conjure_black_pudding">conjure black pudding</Link>, 7th-<Link to="/spell/statue">statue</Link> (looking like a stalagmite or stalactite), 8th-<Link to="/spell/earthquake">earthquake</Link>, 9th-<Link to="/spell/imprisonment">imprisonment</Link>.</p>
</>};
const _crocodile = {title: "Crocodile", jsx: <><h2 id="druiddomain-crocodile-crocodile-domain">Crocodile Domain</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 24</Link></p>
<p><strong>Granted Powers:</strong> You are connected with the primal forces of creation and destruction and with the crocodile spirit's ancient wisdom.</p>
<p><strong>Familiar:</strong> You gain a <Link to="/monster/dwarf_caiman">dwarf caiman</Link> <Link to="/sidekick/familiar">familiar</Link>. Your effective wizard level for this ability is equal to your druid level. Your druid level stacks with levels from other classes that grant familiars when determining the powers of your familiar.</p>
<p><strong>Death Roll (Ex):</strong> While grappling an enemy up to one size category larger than you, you may make a grapple check to roll wildly, knocking your enemy prone and dealing 1d8 points of damage. When using this ability, you gain a bonus to your CMB equal to one half your druid level (minimum 1). You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Ambush (Ex):</strong> At 6th level, you gain <Link to="/ability/sneak_attack">sneak attack</Link> +1d6. This increase to sneak attack damage stacks with sneak attack damage you may have from other sources. This sneak attack damage increases by +1d6 for every 5 druid levels you possess beyond 6th, to a maximum of +3d6 at 16th level.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/touch_of_the_sea">touch of the sea</Link>, 2nd-<Link to="/spell/savage_maw">savage maw</Link>, 3rd-<Link to="/spell/water_walk">water walk</Link>, 4th-<Link to="/spell/strong_jaw">strong jaw</Link>, 5th-<Link to="/spell/legend_lore">legend lore</Link>, 6th-<Link to="/spell/mass_owls_wisdom">mass owl's wisdom</Link>, 7th-<Link to="/spell/true_seeing">true seeing</Link>, 8th-<Link to="/spell/mass_heal">mass heal</Link>, 9th-<Link to="/spell/regenerate">regenerate</Link>.</p>
</>};
const _desert = {title: "Desert", jsx: <><h2 id="druiddomain-desert-desert-domain">Desert Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 34</Link></p>
<p><strong>Granted Powers:</strong> The spirits and secrets of the endless wastes are yours to command.</p>
<p><strong>Heat Shimmer (Su):</strong> As a free action, you can surround yourself with heat distortion that acts as the <Link to="/spell/blur">blur</Link> spell. Creatures that strike you in melee while you're using this ability are <Link to="/misc/dazzled">dazzled</Link> for 1 round (Fortitude negates). You may use this ability for a number of rounds per day equal to 3 + your Wisdom modifier. These rounds need not be consecutive.</p>
<p><strong>Servant of the Sands (Sp):</strong> At 8th level, once per day, you may call upon the aid of a <Link to="/monster/janni">janni</Link> as if using <Link to="/spell/lesser_planar_ally">lesser planar ally</Link>. At 12th level, you may call upon the aid of any type of common (non-noble) <Link to="/family/genie">genie</Link> as if using <Link to="/spell/planar_ally">planar ally</Link>. At 16th level, you may call upon the aid of a noble genie as if using <Link to="/spell/greater_planar_ally">greater planar ally</Link>. If you use this power while in desert terrain, you need not make an offering to call the creature(s), and the cost of any service is halved.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/cloak_of_shade">cloak of shade</Link>, 2nd-<Link to="/spell/shifting_sand">shifting sand</Link>, 3rd-<Link to="/spell/cup_of_dust">cup of dust</Link>, 4th-<Link to="/spell/hallucinatory_terrain">hallucinatory terrain</Link>, 5th-<Link to="/spell/transmute_rock_to_mud">transmute rock to mud</Link> (creates loose sand instead of mud), 6th-<Link to="/spell/sirocco">sirocco</Link>, 7th-<Link to="/spell/sunbeam">sunbeam</Link>, 8th-<Link to="/spell/sunburst">sunburst</Link>, 9th-<Link to="/spell/horrid_wilting">horrid wilting</Link>.</p>
</>};
const _eagle = {title: "Eagle", jsx: <><h2 id="druiddomain-eagle-eagle-domain">Eagle Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 34</Link></p>
<p><strong>Granted Powers:</strong> Your spirit soars with the mightiest and noblest of all winged creatures.</p>
<p><strong>Familiar:</strong> You gain a <Link to="/monster/hawk">hawk</Link> <Link to="/sidekick/familiar">familiar</Link>. Your effective wizard level for this ability is equal to your druid level. Your druid level stacks with levels from other classes that grant familiars when determining the powers of your familiar.</p>
<p><strong>Hawkeye (Su):</strong> As a swift action, you may add a bonus equal to half your druid level (minimum +1) on one ranged attack or on one Perception check. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Aerial evasion (Ex):</strong> At 6th level, you gain the <Link to="/ability/evasion">evasion</Link> ability (as a rogue) when you are flying. At 12th level, you gain <Link to="/talent/improved_evasion">improved evasion</Link> while flying.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/aspect_of_the_falcon">aspect of the falcon</Link>, 2nd-<Link to="/spell/eagles_splendor">eagle's splendor</Link>, 3rd-<Link to="/spell/fly">fly</Link>, 4th-<Link to="/spell/river_of_wind">river of wind</Link>, 5th-<Link to="/spell/overland_flight">overland flight</Link>, 6th-<Link to="/spell/eagle_aerie">eagle aerie</Link>, 7th-<Link to="/spell/animal_shapes">animal shapes</Link> (birds only), 8th-<Link to="/spell/sunburst">sunburst</Link>, 9th-<Link to="/spell/winds_of_vengeance">winds of vengeance</Link>.</p>
</>};
const _erosion = {title: "Erosion", jsx: <><h2 id="druiddomain-erosion-erosion-domain">Erosion Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 46</Link></p>
<p><strong>Granted Powers:</strong> You command the crumbling of stone and revel in rust; the decay and destruction of metal and stone over time appeals to and delights you.</p>
<p><strong>Rusting Touch (Su):</strong> You can cause an opponent's metal armor or weapon to become dry and brittle as it magically corrodes and rusts. You make a melee touch attack against a creature wearing metal armor or wielding a metal weapon. If you hit, choose a metal weapon, suit of metal armor, or metal shield carried or worn by that creature. The object takes an amount of hit point damage equal to 1d6 + half your druid level. If the item is not magical, or if your caster level is greater than the item's caster level, this damage bypasses the item's hardness. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Erosion Aura (Su):</strong> At 8th level, you can project an aura of magically enhanced erosion as a standard action. Objects made primarily of metal or stone within this aura lose 10 points of hardness. Magic items retain a minimum hardness equal to twice their enhancement bonus and can attempt a Fortitude saving throw (DC = 10 + half your druid level + your Wisdom modifier) to negate this effect. A construct made primarily of metal or stone must succeed at a Fortitude save or lose all damage reduction and hardness for 1 round. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/expeditious_excavation">expeditious excavation</Link>, 2nd-<Link to="/spell/soften_earth_and_stone">soften earth and stone</Link>, 3rd-<Link to="/spell/disable_construct">disable construct</Link>, 4th-<Link to="/spell/rusting_grasp">rusting grasp</Link>, 5th-<Link to="/spell/transmute_rock_to_mud">transmute rock to mud</Link>, 6th-<Link to="/spell/sympathetic_vibration">sympathetic vibration</Link>, 7th-<Link to="/spell/disintegrate">disintegrate</Link>, 8th-<Link to="/spell/earthquake">earthquake</Link>, 9th-<Link to="/spell/implosion">implosion</Link>.</p>
</>};
const _frog = {title: "Frog", jsx: <><h2 id="druiddomain-frog-frog-domain">Frog Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 34</Link></p>
<p><strong>Granted Powers:</strong> You venerate the elder amphibians that first brought life to land.</p>
<p><strong>Familiar:</strong> You may gain a <Link to="/monster/toad">toad</Link> <Link to="/sidekick/familiar">familiar</Link>. Your effective wizard level for this ability is equal to your druid level. Your druid level stacks with levels from other classes that grant familiars when determining the powers of your familiar.</p>
<p><strong>Sticky Strike (Su):</strong> As a standard action, you can attempt a ranged touch attack with a sticky tendril against a target up to 15 feet away, then use the <Link to="/umr/pull">pull</Link> universal monster ability to pull the target 5 feet toward you. You gain a bonus on the pull's combat maneuver check equal to 1/2 your druid level. If the target is larger than you, you may pull yourself 5 feet toward the target without making a check. The target can remove the tendril by making an opposed Strength check as a standard action, or by dealing enough slashing damage to the tendril (hit points equal to your druid level, Armor Class equal to your touch Armor Class). You can dissolve the tendril as a free action. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Webfoot (Ex):</strong> At 6th level, you gain the <Link to="/umr/amphibious">amphibious</Link> special quality and a swim speed equal to your land speed. At 12th level, you gain a climb speed equal to your land speed.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/jump">jump</Link>, 2nd-<Link to="/spell/delay_poison">delay poison</Link>, 3rd-<Link to="/spell/lily_pad_stride">lily pad stride</Link>, 4th-<Link to="/spell/shout">shout</Link>, 5th-<Link to="/spell/blessing_of_the_salamander">blessing of the salamander</Link>, 6th-<Link to="/spell/confusion">confusion</Link>, 7th-<Link to="/spell/animal_shapes">animal shapes</Link> (amphibians only), 8th-<Link to="/spell/greater_shout">greater shout</Link>, 9th-<Link to="/spell/summon_froghemoth">summon froghemoth</Link>.</p>
</>};
const _jungle = {title: "Jungle", jsx: <><h2 id="druiddomain-jungle-jungle-domain">Jungle Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 34</Link></p>
<p><strong>Granted Powers:</strong> The spirits of the jungle, both of natural guardians and lost civilizations, whisper in your heart.</p>
<p><strong>Brachiation (Ex):</strong> As a free action for a number of rounds per day equal to your druid level, you may climb with a climb speed equal to your land speed, and gain a bonus on Acrobatics checks equal to your druid level. These rounds do not have to be consecutive.</p>
<p><strong>Trap Sense (Ex):</strong> At 3rd level, you gain the <Link to="/ability/trap_sense">trap sense</Link> ability. This is identical to the rogue class ability. Your effective rogue level is equal to your druid level for the purpose of determining your trap sense bonus. Trap sense bonuses gained from multiple classes stack.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/glide">glide</Link>, 2nd-<Link to="/spell/tar_ball">tar ball</Link>, 3rd-<Link to="/spell/venomous_bolt">venomous bolt</Link>, 4th-<Link to="/spell/arboreal_hammer">arboreal hammer</Link>, 5th-<Link to="/spell/blessing_of_the_salamander">blessing of the salamander</Link>, 6th-<Link to="/spell/swarm_skin">swarm skin</Link>, 7th-<Link to="/spell/creeping_doom">creeping doom</Link>, 8th-<Link to="/spell/wall_of_lava">wall of lava</Link>, 9th-<Link to="/spell/shambler">shambler</Link>.</p>
</>};
const _monkey = {title: "Monkey", jsx: <><h2 id="druiddomain-monkey-monkey-domain">Monkey Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 34</Link></p>
<p><strong>Granted Powers:</strong> The balanced wisdom, skill, agility, and playfulness of the monkey are the model for your spiritual discipline.</p>
<p><strong>Familiar:</strong> You gain a <Link to="/monster/monkey">monkey</Link> <Link to="/sidekick/familiar">familiar</Link>. Your effective wizard level for this ability is equal to your druid level. Your druid level stacks with levels from other classes that grant familiars when determining the powers of your familiar.</p>
<p><strong>Monkey Athletics (Su):</strong> As a free action, you may add a competence bonus equal to half your druid level (minimum of +1) on one Acrobatics, Climb, Disable Device, or Sleight of Hand check. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Ranged Legerdemain (Su):</strong> At 6th level, you can use the Disable Device and Sleight of Hand skills at a range of 30 feet. Working at a distance increases the normal skill check DC by 5, and you cannot take 10 on this check. Any object to be manipulated must weigh 5 pounds or less. You can only use this ability if you have at least 1 rank in the skill being used.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/beguiling_gift">beguiling gift</Link>, 2nd-<Link to="/spell/spider_climb">spider climb</Link>, 3rd-<Link to="/spell/cacophonous_call">cacophonous call</Link>, 4th-<Link to="/spell/freedom_of_movement">freedom of movement</Link>, 5th-<Link to="/spell/summon_natures_ally_v">summon nature's ally V</Link> (dire ape or girallon only), 6th-<Link to="/spell/confusion">confusion</Link>, 7th-<Link to="/spell/animal_shapes">animal shapes</Link> (apes and monkeys only), 8th-<Link to="/spell/clenched_fist">clenched fist</Link>, 9th-<Link to="/spell/foresight">foresight</Link>.</p>
</>};
const _mountain = {title: "Mountain", jsx: <><h2 id="druiddomain-mountain-mountain-domain">Mountain Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 35</Link></p>
<p><strong>Granted Powers:</strong> You have mastered the mighty powers of the great mountains that pierce the sky and stand aloof above the lowlands.</p>
<p><strong>Foothold (Su):</strong> As a standard action, you can cause an adjacent stone surface up to 10 feet square to mold itself into ridges and creases. A foothold that is created on a horizontal surface is treated as <Link to="/rule/difficult_terrain">difficult terrain</Link>, and a Medium or smaller creature standing in the area or moving through it takes a -2 penalty on Acrobatics checks and to CMD due to poor footing. A foothold that is created on a vertical surface grants a +10 bonus on Climb checks to climb it. The stone remains altered for 1 hour. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Thin Air (Su):</strong> At 8th level, as a free action, you can surround yourself with a 5-foot aura of supernaturally thin air that draws the breath from creatures adjacent to you. Creatures beginning their turn in the aura are <Link to="/misc/fatigued">fatigued</Link> (Fortitude negates). A fatigued creature that begins its turn in the aura must save or suffer from <Link to="/rule/altitude_sickness">altitude sickness</Link>, taking 1 point of ability damage to all ability scores. At 16th level, the aura increases to 10 feet. Creatures that do not breathe are immune to this aura. You can use this ability for a number of rounds per day equal to your druid level; the rounds need not be consecutive.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/stone_fist">stone fist</Link>, 2nd-<Link to="/spell/stone_call">stone call</Link>, 3rd-<Link to="/spell/cloak_of_winds">cloak of winds</Link>, 4th-<Link to="/spell/stoneskin">stoneskin</Link>, 5th-<Link to="/spell/geyser">geyser</Link>, 6th-<Link to="/spell/suffocation">suffocation</Link>, 7th-<Link to="/spell/flesh_to_stone">flesh to stone</Link>, 8th-<Link to="/spell/reverse_gravity">reverse gravity</Link>, 9th-<Link to="/spell/clashing_rocks">clashing rocks</Link>.</p>
</>};
const _panther = {title: "Panther", jsx: <><h2 id="druiddomain-panther-panther-domain">Panther Domain</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 25</Link></p>
<p><strong>Granted Powers:</strong> You share the power of the Hunter in Darkness. The potent magic of an ancient predator spirit flows through you.</p>
<p><strong>Hunter's Senses (Ex):</strong> You gain the ability to augment your senses on command. As a standard action, you grant yourself the scent special ability and improved vision. If you have normal vision, you gain low-light vision. If you have low-light vision, you gain darkvision out to a range of 30 feet. If you have darkvision, the range of your darkvision increases by 30 feet. You may use this ability a number of minutes per day equal to your druid level, in 1 minute increments. Dismissing these augmented senses is a free action.</p>
<p><strong>Move in Darkness (Ex):</strong> At 8th level, in areas of normal or magical darkness, you gain a +2 bonus on Stealth skill checks and initiative checks for every 4 druid levels you possess, to a maximum bonus of +10 at 20th level.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/true_strike">true strike</Link>, 2nd-<Link to="/spell/darkness">darkness</Link>, 3rd-<Link to="/spell/deeper_darkness">deeper darkness</Link>, 4th-<Link to="/spell/moonstruck">moonstruck</Link>, 5th-<Link to="/spell/commune_with_nature">commune with nature</Link>, 6th-<Link to="/spell/mislead">mislead</Link>, 7th-<Link to="/spell/true_seeing">true seeing</Link>, 8th-<Link to="/spell/nine_lives">nine lives</Link>, 9th-<Link to="/spell/greater_spell_immunity">greater spell immunity</Link>.</p>
</>};
const _plains = {title: "Plains", jsx: <><h2 id="druiddomain-plains-plains-domain">Plains Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 35</Link></p>
<p><strong>Granted Powers:</strong> The wide open spaces of the prairie, savanna, and steppe are yours to master.</p>
<p><strong>Migrating Herd (Su):</strong> When you summon an <Link to="/monster/aurochs">aurochs, bison</Link>, <Link to="/monster/elephant">elephant, mastodon</Link>, <Link to="/monster/horse">horse</Link>, <Link to="/monster/pony">pony</Link>, or similar quadruped herbivore with a summoning spell, the duration of the spell is increased by 100% (this does not stack with <Link to="/feat/extend_spell">Extend Spell</Link>). The creature's land speed is increased by 10 feet.</p>
<p><strong>Pounce (Ex):</strong> At 6th level, you may use the <Link to="/umr/pounce">pounce</Link> special attack once per day. You may pounce one additional time per day for every 3 levels after 6th.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/mount">mount</Link>, 2nd-<Link to="/spell/chameleon_stride">chameleon stride</Link>, 3rd-<Link to="/spell/haste">haste</Link>, 4th-<Link to="/spell/aspect_of_the_stag">aspect of the stag</Link>, 5th-<Link to="/spell/control_winds">control winds</Link>, 6th-<Link to="/spell/find_the_path">find the path</Link>, 7th-<Link to="/spell/whirlwind">whirlwind</Link>, 8th-<Link to="/spell/animal_shapes">animal shapes</Link>, 9th-<Link to="/spell/world_wave">world wave</Link>.</p>
</>};
const _plane_of_air = {title: "Plane of Air", jsx: <><h2 id="druiddomain-plane_of_air-plane-of-air-domain">Plane of Air Domain</h2>
<p><strong>Sources</strong> <Link to="/source/planes_of_power">Planes of Power pg. 6</Link></p>
<p><strong>Granted Powers:</strong> You draw your power from the boundless expanse of air and clouds. In addition, Fly is a class skill for you, and you can take ranks in the skill even without first having a reliable means to fly or glide. In addition, you can use wild empathy to influence a creature with the air subtype if its Intelligence score is 1 or 2.</p>
<p><strong>Aerial Agility (Ex):</strong> You can navigate the air unhindered. As a free action, you automatically succeed at your Wisdom check to change your direction in an area of subjective gravity, and you can increase or decrease your falling speed by 10 feet per druid level during the first round after you change the direction of gravity. When you are in areas of light, normal, or heavy gravity, activating this ability instead grants you a bonus equal to your druid level on Fly checks and Acrobatics checks to jump for a number of rounds equal to your Wisdom modifier. You can use this ability a number of times equal to 3 + your Wisdom modifier.</p>
<p><strong>Wind Savant (Su):</strong> At 8th level, you treat the penalties from natural or magical wind effects as two steps less severe. In addition, you are surrounded by a cushion of air that grants you a bonus equal to 1/2 your druid level on saving throws against gases, gaseous breath weapons, inhaled poisons, and similar effects.</p>
<p>Alternatively, you can choose to gain a <Link to="/monster/small_air_elemental">Small air elemental</Link> as a <Link to="/sidekick/familiar">familiar</Link>. as if you possessed the <Link to="/feat/improved_familiar">Improved Familiar</Link> feat. Your effective wizard level for this ability is equal to your druid level and stacks with other classes that grant a familiar.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/feather_fall">feather fall</Link>, 2nd-<Link to="/spell/elemental_speech">elemental speech</Link>, 3rd-<Link to="/spell/fly">fly</Link>, 4th-<Link to="/spell/planar_adaptation">planar adaptation</Link>, 5th-<Link to="/spell/overland_flight">overland flight</Link>, 6th-<Link to="/spell/mass_planar_adaptation">mass planar adaptation</Link>, 7th-<Link to="/spell/mass_fly">mass fly</Link>, 8th-<Link to="/spell/mass_invisibility">mass invisibility</Link>, 9th-<Link to="/spell/winds_of_vengeance">winds of vengeance</Link>.</p>
</>};
const _plane_of_earth = {title: "Plane of Earth", jsx: <><h2 id="druiddomain-plane_of_earth-plane-of-earth-domain">Plane of Earth Domain</h2>
<p><strong>Sources</strong> <Link to="/source/planes_of_power">Planes of Power pg. 6</Link></p>
<p><strong>Granted Powers:</strong> You can navigate the untold wonders of the Plane of Earth with ease. In addition, you can use wild empathy to influence a creature with the earth subtype if its Intelligence score is 1 or 2.</p>
<p><strong>Spelunker (Su):</strong> You ably clamber through underground areas. As a free action, you can ignore <Link to="/rule/difficult_terrain">difficult terrain</Link> from stony surfaces, you take no penalties for squeezing through rocky areas, and you gain damage reduction 5/- against rocky hazards such as spike growth. This effect lasts for 1 round, and you can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>One with the Stone (Su):</strong> At 8th level as a swift action, you gain the <Link to="/umr/earth_glide">earth glide</Link> universal monster ability with a speed equal to your base speed. You can breathe normally while using this ability. You can use this ability for a number of rounds per day equal to your druid level, and these rounds don't need to be consecutive.</p>
<p>Alternatively, you can choose to gain a <Link to="/monster/small_earth_elemental">Small earth elemental</Link> as a <Link to="/sidekick/familiar">familiar</Link>. as if you possessed the <Link to="/feat/improved_familiar">Improved Familiar</Link> feat. Your effective wizard level for this ability is equal to your druid level and stacks with other classes that grant a familiar.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/stone_fist">stone fist</Link>, 2nd-<Link to="/spell/elemental_speech">elemental speech</Link>, 3rd-<Link to="/spell/burrow">burrow</Link>, 4th-<Link to="/spell/planar_adaptation">planar adaptation</Link>, 5th-<Link to="/spell/passwall">passwall</Link>, 6th-<Link to="/spell/mass_planar_adaptation">mass planar adaptation</Link>, 7th-<Link to="/spell/stone_to_flesh">stone to flesh</Link>, 8th-<Link to="/spell/repel_metal_or_stone">repel metal or stone</Link>, 9th-<Link to="/spell/clashing_rocks">clashing rocks</Link>.</p>
</>};
const _plane_of_fire = {title: "Plane of Fire", jsx: <><h2 id="druiddomain-plane_of_fire-plane-of-fire-domain">Plane of Fire Domain</h2>
<p><strong>Sources</strong> <Link to="/source/planes_of_power">Planes of Power pg. 7</Link></p>
<p><strong>Granted Powers:</strong> You embrace the destructive flames and ever-roaring volcanoes of the Plane of Fire, having proven yourself impervious to its heat. In addition, you can use wild empathy to influence a creature with the fire subtype if its Intelligence score is 1 or 2.</p>
<p><strong>Fire Hardened (Ex):</strong> You ignore fire damage from the fire-dominant planar trait, and you gain fire resistance 5. If you have natural fire resistance, it increases by 5 instead, and if you are naturally immune to fire, you heal hit points and ability damage at twice the normal rate when resting on a fire-dominant plane. You can touch a willing creature to grant these benefits for 1 hour. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>All-Consuming Flames (Su):</strong> At 8th level, you can channel the extraplanar heat into your allies' weapons within 30 feet as a standard action. For 1 minute, the affected weapons gain the cold-outsider-<Link to="/magic-enh/bane">bane</Link>, fire-outsider-bane, or <Link to="/magic-enh/flaming">flaming</Link> weapon special abilities. You must grant each weapon the same ability, and this ability affects no more than two of any ally's weapons. You can use this ability once per day, plus an additional time per day for every four levels beyond 8th.</p>
<p>Alternatively, you can choose to gain a <Link to="/monster/small_fire_elemental">Small fire elemental</Link> as a <Link to="/sidekick/familiar">familiar</Link>. as if you possessed the <Link to="/feat/improved_familiar">Improved Familiar</Link> feat. Your effective wizard level for this ability is equal to your druid level and stacks with other classes that grant a familiar.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/obscuring_mist">obscuring mist</Link> (creates smoke), 2nd-<Link to="/spell/elemental_speech">elemental speech</Link>, 3rd-<Link to="/spell/ash_storm">ash storm</Link>, 4th-<Link to="/spell/planar_adaptation">planar adaptation</Link>, 5th-<Link to="/spell/scorching_ash_form">scorching ash form</Link>, 6th-<Link to="/spell/mass_planar_adaptation">mass planar adaptation</Link>, 7th-<Link to="/spell/delayed_blast_fireball">delayed blast fireball</Link>, 8th-<Link to="/spell/destruction">destruction</Link>, 9th-<Link to="/spell/fiery_body">fiery body</Link>.</p>
</>};
const _plane_of_water = {title: "Plane of Water", jsx: <><h2 id="druiddomain-plane_of_water-plane-of-water-domain">Plane of Water Domain</h2>
<p><strong>Sources</strong> <Link to="/source/planes_of_power">Planes of Power pg. 7</Link></p>
<p><strong>Granted Powers:</strong> You are at one with the Plane of Water, able to navigate it and weaponize it at will. In addition, you can use wild empathy to influence a creature with the water subtype if its Intelligence score is 1 or 2.</p>
<p><strong>Aquatic Veil (Su):</strong> As a standard action, you can sheathe your body in a thin layer of water for a number of rounds equal to your Wisdom modifier. This grants you a bonus on Swim checks equal to 1/2 your druid level and allows you to breathe normally underwater. You can end the effect when delivering a touch spell to create a pseudopod of water that extends your effective reach by 5 feet for that attack. When used underwater, the pseudopod instead increases your reach by 10 feet. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Hydraulic Crush (Sp):</strong> At 8th level, you can strike an area with a pressurized blast of water in a 5-foot-radius column 30 feet tall with a range of 60 feet. Creatures in the area take 1d6 bludgeoning damage per druid level and are knocked <Link to="/rule/prone">prone</Link>. When used underwater, the radius and height double, and the effect instead creates a powerful eddy that causes affected creatures to lose their Dexterity bonus to Armor Class for 1 round instead of knocking them prone. A successful Reflex save halves the damage and prevents the secondary effect. You can use this ability once per day, plus an additional time for every 6 levels beyond 8th.</p>
<p>Alternatively, you can choose to gain a <Link to="/monster/small_water_elemental">Small water elemental</Link> as a <Link to="/sidekick/familiar">familiar</Link>. as if you possessed the <Link to="/feat/improved_familiar">Improved Familiar</Link> feat. Your effective wizard level for this ability is equal to your druid level and stacks with other classes that grant a familiar.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/touch_of_the_sea">touch of the sea</Link>, 2nd-<Link to="/spell/elemental_speech">elemental speech</Link>, 3rd-<Link to="/spell/water_breathing">water breathing</Link>, 4th-<Link to="/spell/planar_adaptation">planar adaptation</Link>, 5th-<Link to="/spell/solid_fog">solid fog</Link> (functions underwater), 6th-<Link to="/spell/mass_planar_adaptation">mass planar adaptation</Link>, 7th-<Link to="/spell/fluid_form">fluid form</Link>, 8th-<Link to="/spell/seamantle">seamantle</Link>, 9th-<Link to="/spell/tsunami">tsunami</Link>.</p>
</>};
const _ruins = {title: "Ruins", jsx: <><h2 id="druiddomain-ruins-ruins-domain">Ruins Domain</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex pg. 35</Link></p>
<p><strong>Granted Powers:</strong> You sense nature's creeping reclamation of what once belonged to the civilized world and understand how to ensure ruins that hold power or significance will persist.</p>
<p><strong>Ruin Touch (Su):</strong> You can strengthen or weaken objects with your touch. With a melee touch attack, you can increase or decrease the hardness of an object (up to a 10-foot cube) or construct by an amount equal to half your druid level (minimum 1) for 1 minute. You cannot reduce an object's hardness below 0, and the same target cannot be affected by this ability more than once. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Remembrance (Sp):</strong> At 4th level, when within a ruin or other structure that is no longer claimed by civilization, you can call upon the wisdom of the land and its long-dead residents. Once per day for every 4 druid levels you possess, you can cast <Link to="/spell/divination">divination</Link> as a spell-like ability. Additionally, if you are within ruins when you cast <Link to="/spell/commune_with_nature">commune with nature</Link>, you gain information about the crumbling structures around you as though they were part of nature.</p>
<p><strong>Surefooted (Ex):</strong> At 8th level, your speed is not reduced by <Link to="/rule/difficult_terrain">difficult terrain</Link> unless the terrain has been magically manipulated to impede motion.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/magic_stone">magic stone</Link>, 2nd-<Link to="/spell/stone_call">stone call</Link>, 3rd-<Link to="/spell/meld_into_stone">meld into stone</Link>, 4th-<Link to="/spell/rusting_grasp">rusting grasp</Link>, 5th-<em>commune with nature,</em> 6th-<Link to="/spell/stone_tell">stone tell</Link>, 7th-<Link to="/spell/statue">statue</Link>, 8th-<Link to="/spell/earthquake">earthquake</Link>, 9th-<Link to="/spell/clashing_rocks">clashing rocks</Link>.</p>
</>};
const _serpent = {title: "Serpent", jsx: <><h2 id="druiddomain-serpent-serpent-domain">Serpent Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 35</Link></p>
<p><strong>Granted Powers:</strong> You serve ancient serpentine mysteries whose coils still encircle the world.</p>
<p><strong>Familiar:</strong> You gain a <Link to="/monster/viper">viper</Link> <Link to="/sidekick/familiar">familiar</Link>. Your effective wizard level for this ability is equal to your druid level. Your druid level stacks with levels from other classes that grant familiars when determining the powers of your familiar.</p>
<p><strong>Slither (Ex):</strong> As a free action, you can distend and stretch your body to fit easily through narrow spaces for 1 round. You can move freely through a tight space that would normally require a creature of your size to <Link to="/misc/squeeze">squeeze</Link> through. While slithering, you gain a +2 dodge bonus to Armor Class against attacks of opportunity provoked by your movement and a +2 bonus on CMB and on Escape Artist checks made to escape from a grapple. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Venom Immunity (Ex):</strong> At 6th level, you gain immunity to poisons from snakes, reptiles, and creatures with the reptilian subtype. At 12th level, you gain immunity to all poisons.</p>
<p>This replaces <strong className="hl">venom immunity</strong>.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/charm_animal">charm animal</Link>, 2nd-<Link to="/spell/animal_trance">animal trance</Link>, 3rd-<Link to="/spell/poison">poison</Link>, 4th-<Link to="/spell/strong_jaw">strong jaw</Link>, 5th-<Link to="/spell/snake_staff">snake staff</Link>, 6th-<Link to="/spell/charm_monster">charm monster</Link>, 7th-<Link to="/spell/animal_shapes">animal shapes</Link> (reptiles and snakes only), 8th-<Link to="/spell/scintillating_pattern">scintillating pattern</Link>, 9th-<Link to="/spell/crushing_hand">crushing hand</Link>.</p>
</>};
const _swamp = {title: "Swamp", jsx: <><h2 id="druiddomain-swamp-swamp-domain">Swamp Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 35</Link></p>
<p><strong>Granted Powers:</strong> The sour-sweet depths of bogs, marshes, and swamps are your places of power.</p>
<p><strong>Natural Healing (Su):</strong> You can <Link to="/ability/channel_energy">channel energy</Link> (as a cleric of your druid level) a number of times per day equal to 3 + your Charisma modifier, but only to heal animals, plants, and vermin. You may reduce the number of dice healed to cure ability damage (your choice) to all affected creatures, curing 1 point of ability damage for each d6 that the channel energy is reduced. You can take other feats to add to this ability, such as <Link to="/feat/extra_channel">Extra Channel</Link>, but not feats that alter this ability, such as <Link to="/feat/elemental_channel">Elemental Channel</Link> and <Link to="/feat/alignment_channel">Alignment Channel</Link>.</p>
<p><strong>Reed Hunter (Ex):</strong> At 6th level, you gain <Link to="/umr/blindsense">blindsense</Link> 30 feet with respect to <Link to="/rule/concealment">concealment</Link> and <Link to="/rule/cover">cover</Link> from fog, vegetation, or water. At 12th level, this improves to <Link to="/umr/blindsight">blindsight</Link> 30 feet with respect to these conditions.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/hydraulic_push">hydraulic push</Link>, 2nd-<Link to="/spell/burst_of_nettles">burst of nettles</Link>, 3rd-<Link to="/spell/lily_pad_stride">lily pad stride</Link>, 4th-<Link to="/spell/cape_of_wasps">cape of wasps</Link>, 5th-<Link to="/spell/insect_plague">insect plague</Link>, 6th-<Link to="/spell/mass_fester">mass fester</Link>, 7th-<Link to="/spell/animate_plants">animate plants</Link>, 8th-<Link to="/spell/blood_mist">blood mist</Link>, 9th-<Link to="/spell/shambler">shambler</Link>.</p>
</>};
const _the_uskbond = {title: "The Uskbond", jsx: <><h2 id="druiddomain-the_uskbond-the-uskbond-domain">The Uskbond Domain</h2>
<p><strong>Sources</strong> <Link to="/source/horror_realms">Horror Realms pg. 45</Link></p>
<p><strong>Granted Powers:</strong> The Uskbond functions as a unique domain with the granted powers and domain spells below. A druid who takes the Uskbond must be neutral evil and worship <Link to="/faith/zon_kuthon">Zon-Kuthon</Link>. A druid who has taken an archetype that alters or replaces nature bond cannot take the Uskbond.</p>
<p><strong>Absorb Pain (Su):</strong> Whenever you take lethal damage, you can choose as an immediate action to convert a number of points of this damage equal to 1d6 + your Wisdom modifier into nonlethal damage. When you use this ability, you gain a +4 profane bonus on all saving throws versus pain effects during the following round. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Gruesome Display (Ex):</strong> At 8th level, as a standard action you can alter your appearance in such intense, horrific ways that onlookers become <Link to="/misc/nauseated">nauseated</Link>. One creature you select within 30 feet who can see you must succeed at a Will save (DC = 10 + 1/2 your druid level + your Wisdom modifier) or be nauseated for a number of rounds equal to 1/2 your druid level. Every 2 levels beyond 8th, you can affect one additional creature, to a maximum of seven targets within 30 feet at 20th level. Each time you activate your gruesome display, you must affect at least one target, but you can choose to affect fewer targets than your maximum. Once you've targeted the maximum number of creatures granted by level (regardless of whether they successfully save to resist the effect or not), you cannot use gruesome display again for the remainder of the day. This is a mind-affecting fear effect.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/delay_pain">delay pain</Link>, 2nd-<Link to="/spell/lesser_curse_terrain">lesser curse terrain</Link>, 3rd-<Link to="/spell/excruciating_deformation">excruciating deformation</Link>, 4th-<Link to="/spell/curse_terrain">curse terrain</Link>, 5th-<Link to="/spell/symbol_of_pain">symbol of pain</Link>, 6th-<Link to="/spell/greater_curse_terrain">greater curse terrain</Link>, 7th-<Link to="/spell/verminous_transformation">verminous transformation</Link>, 8th-<Link to="/spell/supreme_curse_terrain">supreme curse terrain</Link>, 9th-<Link to="/spell/maze_of_madness_and_suffering">maze of madness and suffering</Link> (haunted forest only).</p>
</>};
const _vermin = {title: "Vermin", jsx: <><h2 id="druiddomain-vermin-vermin-domain">Vermin Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 46</Link>, <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex pg. 35</Link></p>
<p><strong>Granted Powers:</strong> You see the perfection of nature in the spindly limbs and strange forms of all vermin, great and small alike.</p>
<p><strong>Vermin Whisperer (Su):</strong> You can use your <Link to="/ability/wild_empathy">wild empathy</Link> ability on vermin. When you do so, you impart a modicum of implanted intelligence on the vermin, allowing you to interact with vermin as if they were animals. Vermin whisperer functions only on vermin that are mindless or have an Intelligence score of 2 or lower.</p>
<p><strong>Sudden Sting (Su):</strong> At 8th level, you can inflict a lingering, painful sting as a swift action that requires a successful melee touch attack. This sting deals 1d4 points of piercing damage plus 1 point for every 2 druid levels you have, and the target must succeed at a Fortitude save (DC = 10 + half your druid level + your Constitution modifier) or become staggered for 1 round. This is a pain effect. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/ant_haul">ant haul</Link>, 2nd-<Link to="/spell/summon_swarm">summon swarm</Link>, 3rd-<Link to="/spell/vermin_shape_i">vermin shape I</Link>, 4th-<Link to="/spell/vermin_shape_ii">vermin shape II</Link>, 5th-<Link to="/spell/insect_plague">insect plague</Link>, 6th-<Link to="/spell/swarm_skin">swarm skin</Link>, 7th-<Link to="/spell/creeping_doom">creeping doom</Link>, 8th-<Link to="/spell/verminous_transformation">verminous transformation</Link>, 9th-<Link to="/spell/summon_natures_ally_ix">summon nature's ally IX</Link> (1d3 purple worms only).</p>
</>};
const _vulture = {title: "Vulture", jsx: <><h2 id="druiddomain-vulture-vulture-domain">Vulture Domain</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 25</Link></p>
<p><strong>Granted Powers:</strong> Yours is the power of death and rebirth. Your spirit soars above all and moves with the flow of unseen currents.</p>
<p><strong>Death's Companion (Ex):</strong> Your totem grants you protection from the harbingers of death. As an immediate action, you gain a +2 bonus on saving throws against disease, death spells, and death effects that lasts a number of rounds equal to your druid level. This bonus increases by 2 at 6th level and every 5 levels thereafter, to a maximum of +8 at 16th level. You may use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Agent of Rebirth (Sp):</strong> At 8th level, you may expend a quantity of special oils worth 1,000 gp to cast <Link to="/spell/reincarnate">reincarnate</Link> as a spell-like ability usable once per day. Additionally, when using this ability or casting reincarnate as a prepared spell, you have some influence over the physical form that the reincarnated spirit will take. When rolling against the spell's incarnation table, you may roll twice and choose between the two results.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/deathwatch">deathwatch</Link>, 2nd-<Link to="/spell/glide">glide</Link>, 3rd-<Link to="/spell/death_knell">death knell</Link>, 4th-<Link to="/spell/death_ward">death ward</Link>, 5th-<Link to="/spell/breath_of_life">breath of life</Link>, 6th-<Link to="/spell/circle_of_death">circle of death</Link>, 7th-<Link to="/spell/resurrection">resurrection</Link>, 8th-<Link to="/spell/finger_of_death">finger of death</Link>, 9th-<Link to="/spell/winds_of_vengeance">winds of vengeance</Link>.</p>
</>};
const _wolf = {title: "Wolf", jsx: <><h2 id="druiddomain-wolf-wolf-domain">Wolf Domain</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 36</Link></p>
<p><strong>Granted Powers:</strong> You run with the pack and are the master of the cold hunt of your spirit totem.</p>
<p><strong>Improved Trip:</strong> You gain <Link to="/feat/improved_trip">Improved Trip</Link> as a bonus feat.</p>
<p><strong>Pack Tactics (Ex):</strong> At 8th level, as a free action on your turn, you can designate an adjacent square; your attacks are treated as coming from that square for the purposes of determining whether or not you are flanking (this applies even if that square is occupied by an object or creature). This ends at the start of your next turn or if you move. If you are flanking a creature without using this ability, you may add your Wisdom bonus to your attack roll rather than the normal +2 flanking bonus. You can use this ability a number of times per day equal to 3 + your Wisdom modifier.</p>
<p><strong>Domain Spells:</strong> 1st-<Link to="/spell/hunters_howl">hunter's howl</Link>, 2nd-<Link to="/spell/bloodhound">bloodhound</Link>, 3rd-<Link to="/spell/aspect_of_the_wolf">aspect of the wolf</Link>, 4th-<Link to="/spell/strong_jaw">strong jaw</Link>, 5th-<Link to="/spell/tireless_pursuers">tireless pursuers</Link>, 6th-<Link to="/spell/find_the_path">find the path</Link>, 7th-<Link to="/spell/animal_shapes">animal shapes</Link> (canines only), 8th-<Link to="/spell/phantasmal_revenge">phantasmal revenge</Link>, 9th-<Link to="/spell/freedom">freedom</Link>.</p>
</>};
export default {not_found:_not_found,aquatic:_aquatic,arctic:_arctic,badlands:_badlands,cave:_cave,crocodile:_crocodile,desert:_desert,eagle:_eagle,erosion:_erosion,frog:_frog,jungle:_jungle,monkey:_monkey,mountain:_mountain,panther:_panther,plains:_plains,plane_of_air:_plane_of_air,plane_of_earth:_plane_of_earth,plane_of_fire:_plane_of_fire,plane_of_water:_plane_of_water,ruins:_ruins,serpent:_serpent,swamp:_swamp,the_uskbond:_the_uskbond,vermin:_vermin,vulture:_vulture,wolf:_wolf}